+        assert_eq!(format!("{:?}", TlsState::Handshaking), "Handshaking");
+        assert_eq!(format!("{:?}", TlsState::Ready), "Ready");
+        assert_eq!(format!("{:?}", TlsState::ShuttingDown), "ShuttingDown");
+        assert_eq!(format!("{:?}", TlsState::Closed), "Closed");
+    }
